SELECT test_description
FROM performance_tests
WHERE test_status = 'completed';

SELECT COUNT(*) 
FROM performance_tests 
WHERE test_date LIKE '2023-10-01%';

SELECT test_description, test_date
FROM performance_tests
WHERE test_id = 1;

SELECT test_status
FROM performance_tests
WHERE test_id = 1;

SELECT test_date, energy, test_description, test_environment
FROM performance_tests
WHERE speedup > 1;

SELECT AVG(power) AS average_power, test_status
FROM performance_tests
WHERE test_status = 'in progress';

SELECT username
FROM users
WHERE last_login > created_at;

SELECT benchmark_id 
FROM test_benchmarks 
WHERE test_id = 0;

SELECT AVG(energy) as average_energy, AVG(power) as average_power
FROM performance_tests
WHERE speedup = (SELECT MAX(speedup) FROM performance_tests);

SELECT AVG(pt.energy) AS average_fuel_consumption
FROM performance_tests pt
WHERE pt.test_description = 'Baseline test';

SELECT energy
FROM performance_tests
WHERE test_description = 'Optimized test';
